#include <stdio.h>
#include <stdbool.h>
#define MAX_N 20

bool is_valid(int graph[MAX_N][MAX_N], int colour[], int vertex, int colour_idx, int N) {
    for (int i = 0; i < N; ++i) {
        if (graph[vertex][i] && colour[i] == colour_idx) return false;
    }
    return true;
}

bool can_colour(int graph[MAX_N][MAX_N], int colour[], int vertex, int M, int N) {
    if (vertex == N) return true;
    for (int c = 0; c < M; ++c) {
        if (is_valid(graph, colour, vertex, c, N)) {
            colour[vertex] = c;
            if (can_colour(graph, colour, vertex + 1, M, N)) return true;
            colour[vertex] = -1;
        }
    }
    return false;
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N, M, E; scanf("%d %d %d", &N, &M, &E);
        int graph[MAX_N][MAX_N] = {0};
        for (int i = 0; i < E; ++i) {
            int u, v; scanf("%d %d", &u, &v);
            graph[u][v] = graph[v][u] = 1;
        }
        int colour[MAX_N];
        for (int i = 0; i < N; ++i) colour[i] = -1;
        if (can_colour(graph, colour, 0, M, N)) printf("true\n");
        else printf("false\n");
    }
    return 0;
}

