#include <bits/stdc++.h>
using namespace std;

bool isValid(const vector<vector<int>>& g, const vector<int>& col, int v, int c) {
    for (int i = 0; i < (int)g.size(); ++i) {
        if (g[v][i] && col[i] == c) return false;
    }
    return true;
}

bool dfs(vector<vector<int>>& g, vector<int>& col, int v, int M) {
    int N = g.size();
    if (v == N) return true;
    for (int c = 0; c < M; ++c) {
        if (isValid(g, col, v, c)) {
            col[v] = c;
            if (dfs(g, col, v + 1, M)) return true;
            col[v] = -1;
        }
    }
    return false;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int N, M, E; cin >> N >> M >> E;
        vector<vector<int>> g(N, vector<int>(N, 0));
        for (int i = 0; i < E; ++i) {
            int u, v; cin >> u >> v;
            g[u][v] = g[v][u] = 1;
        }
        vector<int> col(N, -1);
        cout << (dfs(g, col, 0, M) ? "true" : "false") << '\n';
    }
    return 0;
}

