import java.io.*;
import java.util.*;

public class Main {
    private static boolean isValid(int[][] g, int[] col, int v, int c) {
        for (int i = 0; i < g.length; i++) {
            if (g[v][i] == 1 && col[i] == c) return false;
        }
        return true;
    }

    private static boolean dfs(int[][] g, int[] col, int v, int M) {
        if (v == g.length) return true;
        for (int c = 0; c < M; c++) {
            if (isValid(g, col, v, c)) {
                col[v] = c;
                if (dfs(g, col, v + 1, M)) return true;
                col[v] = -1;
            }
        }
        return false;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int M = Integer.parseInt(st.nextToken());
            int E = Integer.parseInt(st.nextToken());
            int[][] g = new int[N][N];
            for (int i = 0; i < E; i++) {
                st = new StringTokenizer(br.readLine());
                int u = Integer.parseInt(st.nextToken());
                int v = Integer.parseInt(st.nextToken());
                g[u][v] = g[v][u] = 1;
            }
            int[] col = new int[N];
            Arrays.fill(col, -1);
            System.out.println(dfs(g, col, 0, M) ? "true" : "false");
        }
    }
}

