import sys

def is_valid(g, colour, v, c):
    for i, adj in enumerate(g[v]):
        if adj and colour[i] == c:
            return False
    return True

def dfs(g, colour, v, M):
    if v == len(g):
        return True
    for c in range(M):
        if is_valid(g, colour, v, c):
            colour[v] = c
            if dfs(g, colour, v + 1, M):
                return True
            colour[v] = -1
    return False

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it)); E = int(next(it))
        g = [[0]*N for _ in range(N)]
        for _ in range(E):
            u = int(next(it)); v = int(next(it))
            g[u][v] = g[v][u] = 1
        colour = [-1]*N
        out_lines.append('true' if dfs(g, colour, 0, M) else 'false')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

